import time
import random
import logging
from functools import wraps
from typing import Callable, Type

logger = logging.getLogger(__name__)

TRANSIENT_STATUS_CODES = {429, 500, 502, 503, 504}
FATAL_STATUS_CODES = {400, 401, 403, 404, 422}

class TransientError(Exception):
    def __init__(self, message: str, status_code: int = 0):
        super().__init__(message)
        self.status_code = status_code

class PersistentError(Exception):
    def __init__(self, message: str, status_code: int = 0):
        super().__init__(message)
        self.status_code = status_code

class FatalError(Exception):
    pass

def classify_http_error(status_code: int, body: dict) -> Exception:
    if status_code in TRANSIENT_STATUS_CODES:
        return TransientError(f"Transient error: HTTP {status_code}", status_code)
    if status_code in FATAL_STATUS_CODES:
        return PersistentError(f"Persistent error: HTTP {status_code}", status_code)
    return FatalError(f"Unclassified error: HTTP {status_code}")

def exponential_backoff_with_jitter(
    max_attempts: int = 5,
    base_delay: float = 1.0,
    max_delay: float = 60.0,
    jitter_factor: float = 0.25,
    retryable_exceptions: tuple[Type[Exception], ...] = (TransientError,),
):
    def decorator(fn: Callable):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            last_exc = None
            for attempt in range(1, max_attempts + 1):
                try:
                    return fn(*args, **kwargs)
                except retryable_exceptions as exc:
                    last_exc = exc
                    if attempt == max_attempts:
                        logger.error(
                            "max_retries_exceeded",
                            extra={"fn": fn.__name__, "attempts": attempt, "error": str(exc)},
                        )
                        raise
                    delay = min(base_delay * (2 ** (attempt - 1)), max_delay)
                    jitter = random.uniform(-jitter_factor * delay, jitter_factor * delay)
                    sleep_time = max(0, delay + jitter)
                    logger.warning(
                        "retrying_after_transient_error",
                        extra={
                            "fn": fn.__name__,
                            "attempt": attempt,
                            "next_attempt_in_s": round(sleep_time, 2),
                            "error": str(exc),
                        },
                    )
                    time.sleep(sleep_time)
                except (PersistentError, FatalError):
                    raise
            raise last_exc
        return wrapper
    return decorator

@exponential_backoff_with_jitter(max_attempts=5, base_delay=1.0, max_delay=60.0)
def call_llm_api(prompt: str, model: str) -> dict:
    import httpx
    response = httpx.post(
        "https://api.example.com/v1/completions",
        json={"model": model, "prompt": prompt},
        timeout=30.0,
    )
    if not response.is_success:
        exc = classify_http_error(response.status_code, response.json())
        raise exc
    return response.json()

